<nav class="mb-4">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < steps.Length; i++)
        {
            var stepIndex = i;
            var isCompleted = stepIndex < CurrentStep;
            var isCurrent = stepIndex == CurrentStep;
            var isFuture = stepIndex > CurrentStep;
            var clickable = isCompleted;

            <div class="text-center flex-fill" style="z-index: 1;">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepBadgeClass(stepIndex)"
                        style="width: 40px; height: 40px;"
                        disabled="@(!clickable)"
                        @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </button>
                <div class="small mt-1 @(isFuture ? "text-muted" : (isCurrent ? "fw-bold" : ""))">
                    @steps[stepIndex]
                </div>
            </div>
        }
    </div>

    <div class="progress mt-2" style="height: 4px;">
        <div class="progress-bar" role="progressbar"
             style="@($"width: {(CurrentStep) * 25}%")"></div>
    </div>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string StepBadgeClass(int step)
    {
        if (step < CurrentStep) return "btn-success text-white";
        if (step == CurrentStep) return "btn-primary text-white";
        return "btn-outline-secondary";
    }
}

