@page "/apply"
@using sv_319fe3f7f1e84dda9c558784546cb67f.Models
@using sv_319fe3f7f1e84dda9c558784546cb67f.Components.JobApplication
@rendermode InteractiveServer
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (SubmittedApplicationId.HasValue)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">&#10003; Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@SubmittedApplicationId</strong></p>
            <p class="text-muted">Thank you for applying. We will be in touch soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="CurrentStep" OnStepClicked="GoToStep" />

        @switch (CurrentStep)
        {
            case 0:
                <PersonalInfoStep Model="PersonalInfo"
                                  OnNext="NextStep"
                                  ValidateEmail="AppService.ValidateEmailAsync" />
                break;
            case 1:
                <WorkHistoryStep Entries="WorkEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="References"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="CoverLetter"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="PersonalInfo"
                            WorkEntries="WorkEntries"
                            References="References"
                            CoverLetter="CoverLetter"
                            OnBack="PreviousStep"
                            OnEditSection="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int CurrentStep;
    private int? SubmittedApplicationId;

    // Form state owned by this page
    private PersonalInfoModel PersonalInfo = new();
    private List<WorkEntryModel> WorkEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> References = new() { new ReferenceModel(), new ReferenceModel() };
    private string CoverLetter = "";

    private void NextStep() => CurrentStep++;
    private void PreviousStep() => CurrentStep--;

    private void GoToStep(int step)
    {
        if (step < CurrentStep)
            CurrentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            PersonalInfo.ToRecord(),
            new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
            References.Select(r => r.ToRecord()).ToList(),
            CoverLetter
        );

        SubmittedApplicationId = await AppService.SubmitApplicationAsync(application);
    }
}

